// Analyze sailing conditions in 8 compass directions from a position.
// Returns Result: { ok: true, data: { origin, directions } } or { ok: false, error: { code, message } }.
// Each direction includes top-level score/rating/summary (from current conditions)
// plus an hourly[] array with per-hour {score, rating, summary} for timeline animation.
// Fetches are staggered in batches to avoid Open-Meteo burst rate limits.
async function analyzeDirections(lat: number, lon: number) {
  // 8 cardinal/intercardinal directions with their bearings
  const directions = [
    { name: 'N',  bearing: 0 },
    { name: 'NE', bearing: 45 },
    { name: 'E',  bearing: 90 },
    { name: 'SE', bearing: 135 },
    { name: 'S',  bearing: 180 },
    { name: 'SW', bearing: 225 },
    { name: 'W',  bearing: 270 },
    { name: 'NW', bearing: 315 }
  ];

  const sampleDistanceNm = config.get('DIRECTION_SAMPLE_DISTANCE_NM') || 30;
  // Convert nm to km for the Haversine formula (1 nm = 1.852 km)
  const sampleDistanceKm = sampleDistanceNm * 1.852;

  // Calculate destination point given start, bearing, and distance
  function destinationPoint(startLat: number, startLon: number, bearingDeg: number, distKm: number) {
    const R = 6371; // Earth radius in km
    const toRad = (d: number) => d * Math.PI / 180;
    const toDeg = (r: number) => r * 180 / Math.PI;

    const lat1 = toRad(startLat);
    const lon1 = toRad(startLon);
    const brng = toRad(bearingDeg);
    const angDist = distKm / R;

    const lat2 = Math.asin(
      Math.sin(lat1) * Math.cos(angDist) +
      Math.cos(lat1) * Math.sin(angDist) * Math.cos(brng)
    );
    const lon2 = lon1 + Math.atan2(
      Math.sin(brng) * Math.sin(angDist) * Math.cos(lat1),
      Math.cos(angDist) - Math.sin(lat1) * Math.sin(lat2)
    );

    return { lat: toDeg(lat2), lon: toDeg(lon2) };
  }

  // Score a weather snapshot for sailing — returns 0-100 (higher = better).
  // Accepts a flat data object with windSpeed, windGusts, windDirection,
  // waveHeight, precipitation — same shape as weather.current or hourly[i].
  function scoreSnapshot(data: any, headingBearing: number) {
    let score = 100;
    const wind = data.windSpeed; // knots
    const gustFactor = data.windGusts / Math.max(wind, 1);
    const waveHeight = data.waveHeight; // meters, may be null
    const precip = data.precipitation; // mm

    // Wind speed scoring — ideal range 8-20 kn for cruising
    if (wind < 5) score -= 15;          // Too light, not enough to sail
    else if (wind > 30) score -= 50;    // Dangerous — storm conditions
    else if (wind > 25) score -= 35;    // Very strong — experienced only
    else if (wind > 20) score -= 15;    // Brisk but manageable

    // Wind angle relative to heading — headwinds are hardest
    const windDir = data.windDirection;
    const angleDiff = Math.abs(((windDir - headingBearing + 180) % 360) - 180);
    if (angleDiff < 30) score -= 25;       // Dead run — risky with strong winds
    else if (angleDiff > 150) score -= 30; // Close to head wind — slow, exhausting
    else if (angleDiff > 120) score -= 15; // Close hauled — challenging

    // Gust factor — big gusts relative to sustained wind are dangerous
    if (gustFactor > 2.0) score -= 20;
    else if (gustFactor > 1.5) score -= 10;

    // Wave height scoring
    if (waveHeight !== null) {
      if (waveHeight > 4) score -= 40;       // Very rough seas
      else if (waveHeight > 3) score -= 25;  // Rough
      else if (waveHeight > 2) score -= 10;  // Moderate
    }

    // Precipitation penalty — reduces visibility and comfort
    if (precip > 5) score -= 20;       // Heavy rain
    else if (precip > 1) score -= 10;  // Moderate rain
    else if (precip > 0) score -= 5;   // Light drizzle

    return Math.max(0, Math.min(100, score));
  }

  // Map score to color rating
  function getRating(score: number) {
    if (score >= 65) return 'green';
    if (score >= 40) return 'yellow';
    return 'red';
  }

  // Build text summary from a weather snapshot for a direction
  function buildSummary(data: any, headingBearing: number) {
    const parts: string[] = [];
    const wind = data.windSpeed;
    const windDir = data.windDirection;
    const angleDiff = Math.abs(((windDir - headingBearing + 180) % 360) - 180);

    // Wind description
    if (wind < 5) parts.push('Calm winds');
    else if (wind > 30) parts.push(`Storm force ${Math.round(wind)} kn`);
    else if (wind > 25) parts.push(`Strong ${Math.round(wind)} kn`);
    else if (wind > 15) parts.push(`Fresh ${Math.round(wind)} kn`);
    else parts.push(`${Math.round(wind)} kn`);

    // Wind angle description relative to heading
    if (angleDiff > 150) parts.push('headwind');
    else if (angleDiff > 120) parts.push('close hauled');
    else if (angleDiff > 60) parts.push('beam reach');
    else if (angleDiff > 30) parts.push('broad reach');
    else parts.push('downwind');

    // Waves — if available
    const wh = data.waveHeight;
    if (wh !== null && wh > 0.5) {
      parts.push(`${wh.toFixed(1)}m seas`);
    }

    // Rain
    if (data.precipitation > 5) parts.push('heavy rain');
    else if (data.precipitation > 1) parts.push('rain');

    return parts.join(', ');
  }

  // Compute sample points for all 8 directions
  const samplePoints = directions.map(d => destinationPoint(lat, lon, d.bearing, sampleDistanceKm));

  // --- Staggered batch fetching to avoid Open-Meteo burst rate limits ---
  // Instead of 16 simultaneous API calls, process directions in small batches
  // with a short delay between each batch.
  const batchSize = (config.get('DIRECTION_BATCH_SIZE') as number) || 2;
  const batchDelayMs = 250; // pause between batches to let rate limiter recover
  const weatherResults: any[] = new Array(samplePoints.length);

  for (let batchStart = 0; batchStart < samplePoints.length; batchStart += batchSize) {
    const batchEnd = Math.min(batchStart + batchSize, samplePoints.length);

    // Fetch this batch of directions in parallel (small enough to stay under rate limit)
    const batchPromises = [];
    for (let i = batchStart; i < batchEnd; i++) {
      batchPromises.push(
        functions.call('fetchWeather', samplePoints[i].lat, samplePoints[i].lon)
          .then((result: any) => { weatherResults[i] = result; })
      );
    }
    await Promise.all(batchPromises);

    // Delay before next batch — skip delay after the last batch
    if (batchEnd < samplePoints.length) {
      await new Promise(resolve => setTimeout(resolve, batchDelayMs));
    }
  }

  // Check all results — if any fetch failed, propagate the first failure
  const firstFailure = weatherResults.find((r: any) => !r.ok);
  if (firstFailure) {
    return {
      ok: false,
      error: {
        code: 'DIRECTION_ANALYSIS_ERROR',
        message: firstFailure.error.message || 'One or more weather fetches failed'
      }
    };
  }

  // All succeeded — score current conditions and each hourly entry per direction
  const results = directions.map((dir, i) => {
    const weather = weatherResults[i].data;

    // Score current conditions (top-level values)
    const currentScore = scoreSnapshot(weather.current, dir.bearing);

    // Score each hourly forecast entry for timeline animation
    const hourlyScores = weather.hourly.map((hour: any) => {
      const hScore = scoreSnapshot(hour, dir.bearing);
      return {
        score: hScore,
        rating: getRating(hScore),
        summary: buildSummary(hour, dir.bearing)
      };
    });

    return {
      name: dir.name,
      bearing: dir.bearing,
      samplePoint: samplePoints[i],
      score: currentScore,
      rating: getRating(currentScore),
      summary: buildSummary(weather.current, dir.bearing),
      conditions: weather.current,
      hourly: hourlyScores
    };
  });

  // Success — wrap in Result
  return { ok: true, data: { origin: { lat, lon }, directions: results } };
}
