    var hourData = weather.hourly[currentHourIndex] || weather.current;
    var windSpeed = hourData.windSpeed || 0;
    var windDir = hourData.windDirection || 0;
    var precip = hourData.precipitation || 0;
    var temperature = hourData.temperature || 0;

    // Store cloud cover for the dimming overlay
    cloudCover = hourData.cloudCover || 0;

    // --- Wind particles — count scales with wind speed ---
    var windCount = Math.min(Math.floor(windSpeed * 3), 150);
    var windRad = (windDir + 90) * Math.PI / 180;
    for (var i = 0; i < windCount; i++) {
      particles.push({
        type: 'wind',
        x: Math.random() * weatherCanvas.width,
        y: Math.random() * weatherCanvas.height,
        speed: (windSpeed * 0.3 + Math.random() * 2),
        angle: windRad + (Math.random() - 0.5) * 0.3,
        life: Math.random() * 200 + 100,
        maxLife: 300,
        size: 1 + Math.random() * 2
      });
    }

    // --- Wave swell arcs — only when marine wave data is available ---
    if (hourData.waveHeight !== null && hourData.waveHeight > 0) {
      var waveDir = hourData.waveDirection !== null ? hourData.waveDirection : windDir;
      var waveRad = (waveDir + 90) * Math.PI / 180;
      var waveCount = Math.min(Math.floor((hourData.wavePeriod || 5) * 4), 60);

      for (var w = 0; w < waveCount; w++) {
        particles.push({
          type: 'wave',
          x: Math.random() * weatherCanvas.width,
          y: Math.random() * weatherCanvas.height,
          speed: 0.3 + Math.random() * 0.5,
          angle: waveRad + (Math.random() - 0.5) * 0.4,
          life: Math.random() * 300 + 150,
          maxLife: 450,
          size: 4 + hourData.waveHeight * 3 + Math.random() * 4,
          arcStart: Math.random() * Math.PI * 2,
          arcSpan: (0.6 + Math.random() * 0.8) * Math.PI
        });
      }
    }

    // --- Precipitation: snow when cold (< 2°C), rain otherwise ---
    if (precip > 0) {
      if (temperature < 2) {
        var snowCount = Math.min(Math.floor(precip * 40), 250);
        for (var s = 0; s < snowCount; s++) {
          particles.push({
            type: 'snow',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 0.5 + Math.random() * 1.5,
            angle: Math.PI / 2 + (Math.random() - 0.5) * 0.3,
            life: Math.random() * 200 + 100,
            maxLife: 300,
            size: 1.5 + Math.random() * 2.5,
            wobble: Math.random() * Math.PI * 2,
            wobbleSpeed: 0.02 + Math.random() * 0.03
          });
        }
