        var rainCount = Math.min(Math.floor(precip * 40), 250);
        for (var r = 0; r < rainCount; r++) {
          particles.push({
            type: 'rain',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 4 + Math.random() * 4 + precip,
            angle: Math.PI / 2 + (windRad - Math.PI) * 0.15,
            life: Math.random() * 60 + 20,
