  // ===== Timeline Playback =====

  // Advance to the next hour in the forecast timeline.
  // Called on each interval tick during playback.
  function advanceTimeline() {
    if (!currentWeather || !currentWeather.hourly) return;

    var maxIndex = currentWeather.hourly.length - 1;

    // Reached the end — stop playback and reset to beginning
    if (currentHourIndex >= maxIndex) {
      stopPlayback();
      currentHourIndex = 0;
      updateConditionsPanel(currentWeather);
      updateTimeline(currentWeather);
      initParticles(currentWeather);
      updateCompassRose(directionsData, currentHourIndex);
      return;
    }

    // Move one hour forward and refresh all displays
    currentHourIndex++;
    updateConditionsPanel(currentWeather);
    updateTimeline(currentWeather);
    initParticles(currentWeather);
    updateCompassRose(directionsData, currentHourIndex);
  }

  // Start auto-advancing through the timeline
  function startPlayback() {
    if (isPlaying) return;
    if (!currentWeather || !currentWeather.hourly || currentWeather.hourly.length === 0) return;

    isPlaying = true;

    // Update UI: swap to pause icon, add playing class for thumb pulse
    var btn = document.getElementById('timeline-play-btn');
    var slider = document.getElementById('timeline-slider');
    if (btn) {
      btn.textContent = '\u275A\u275A'; // ❚❚ pause icon
      btn.classList.add('playing');
      btn.setAttribute('aria-label', 'Pause forecast animation');
    }
    if (slider) slider.classList.add('playing');

    // If already at the end, reset to start before playing
    var maxIndex = currentWeather.hourly.length - 1;
    if (currentHourIndex >= maxIndex) {
      currentHourIndex = 0;
      updateConditionsPanel(currentWeather);
      updateTimeline(currentWeather);
      initParticles(currentWeather);
      updateCompassRose(directionsData, currentHourIndex);
    }

    // Start the interval timer using the configured speed
    playInterval = setInterval(advanceTimeline, playIntervalMs);
