  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.timeline-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
  font-weight: 600;
}
.timeline-time {
  font-size: 0.8rem;
  font-family: var(--font-mono);
  color: var(--accent);
}

/* ===== Timeline Play/Pause Button ===== */
#timeline-play-btn {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  border: 1.5px solid var(--accent);
  background: var(--accent-dim);
  color: var(--accent);
  font-size: 0.7rem;
