  right: 1rem;
  min-width: 150px;
  padding: 0.6rem 0.75rem;
}
.layer-panel-title {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
  padding-bottom: 0.35rem;
  border-bottom: 1px solid var(--border-color);
}
.layer-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.25rem 0;
}
.layer-toggle {
  -webkit-appearance: none;
  appearance: none;
  width: 16px;
  height: 16px;
  border: 1.5px solid var(--border-color);
  border-radius: 3px;
  background: transparent;
  cursor: pointer;
  position: relative;
  flex-shrink: 0;
  transition: background 0.2s ease, border-color 0.2s ease;
}
.layer-toggle:checked {
  background: var(--accent);
  border-color: var(--accent);
}
.layer-toggle:checked::after {
  content: '\2713';
  position: absolute;
  top: -1px;
  left: 2px;
  font-size: 0.65rem;
  color: var(--bg-dark);
  font-weight: 700;
}
.layer-toggle:hover {
  border-color: var(--accent);
}
.layer-toggle:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.layer-row label {
  font-size: 0.8rem;
  color: var(--text-primary);
  cursor: pointer;
  user-select: none;
}

/* ===== Action Buttons Container (bottom-right) ===== */
#action-buttons {
  position: absolute;
  bottom: 5.5rem;
  right: 1rem;
  z-index: 10;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  align-items: flex-end;
}

/* ===== Shared button base for Refresh & Location ===== */
#action-buttons button {
  background: var(--bg-panel);
  backdrop-filter: blur(12px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  color: var(--accent);
  font-size: 0.8rem;
  font-weight: 600;
  font-family: var(--font);
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
  white-space: nowrap;
}
#action-buttons button:hover {
  background: var(--bg-panel-hover);
  border-color: var(--accent);
}

/* ===== Refresh Button ===== */
#refresh-btn.loading {
  opacity: 0.6;
  pointer-events: none;
}
#refresh-btn .refresh-icon {
  transition: transform 0.5s ease;
}
#refresh-btn.loading .refresh-icon {
  animation: spin 1s linear infinite;
}

/* ===== Location Button ===== */
#location-btn .location-icon {
  font-size: 1rem;
  line-height: 1;
}
#location-btn.loading {
  opacity: 0.6;
  pointer-events: none;
}
#location-btn.loading .location-icon {
  animation: pulse 1s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.5; transform: scale(0.9); }
}

/* ===== Toast Notification ===== */
#toast-container {
  position: fixed;
  bottom: 9rem;
  right: 1rem;
  z-index: 100;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  align-items: flex-end;
  pointer-events: none;
}
.toast {
  pointer-events: auto;
  background: rgba(10, 22, 40, 0.95);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(239, 68, 68, 0.4);
  border-left: 3px solid var(--red);
  border-radius: 8px;
  padding: 0.65rem 1rem;
  color: var(--text-primary);
  font-size: 0.8rem;
  font-family: var(--font);
  line-height: 1.4;
  max-width: 360px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5), 0 0 12px rgba(239, 68, 68, 0.15);
  transform: translateX(110%);
  opacity: 0;
  transition: transform 0.35s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.35s ease;
}
.toast.visible {
  transform: translateX(0);
  opacity: 1;
}
.toast.hiding {
  transform: translateX(110%);
  opacity: 0;
}

/* ===== Beaufort Scale Legend ===== */
.beaufort-indicator {
  display: inline-flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.15rem 0.4rem;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 600;
}
.beaufort-0-3 { background: var(--green-bg); color: var(--green); }
.beaufort-4-5 { background: var(--accent-dim); color: var(--accent); }
.beaufort-6-7 { background: var(--yellow-bg); color: var(--yellow); }
.beaufort-8   { background: var(--red-bg); color: var(--red); }

/* ===== Responsive ===== */
@media (max-width: 768px) {
  #conditions-panel {
    top: auto;
    bottom: 6rem;
    left: 1rem;
    right: 1rem;
    max-width: none;
    min-width: 0;
    display: none;
  }
  #conditions-panel.mobile-visible {
    display: block;
  }
  #compass-panel {
    top: 0.5rem;
    right: 0.5rem;
    width: 200px;
    padding: 0.5rem;
  }
  .compass-rose {
    width: 160px;
    height: 160px;
  }
  #timeline-panel {
    bottom: 0.5rem;
    width: 95vw;
  }
  #info-bar {
    bottom: 4.5rem;
    font-size: 0.65rem;
  }
  #layer-panel {
    bottom: 10rem;
    right: 0.5rem;
    min-width: 130px;
    padding: 0.5rem 0.6rem;
  }
  #action-buttons {
    bottom: 4.5rem;
  }
  #toast-container {
    bottom: 7.5rem;
    right: 0.5rem;
    left: 0.5rem;
    align-items: stretch;
  }
  .toast {
    max-width: none;
  }
  /* Slightly smaller play button on mobile */
  #timeline-play-btn {
    width: 24px;
    height: 24px;
    font-size: 0.6rem;
  }
}

/* ===== Leaflet Overrides ===== */
.leaflet-control-attribution {
  background: var(--bg-panel) !important;
  color: var(--text-muted) !important;
  font-size: 0.6rem !important;
}
.leaflet-control-attribution a {
  color: var(--text-secondary) !important;
}
.leaflet-control-zoom a {
  background: var(--bg-panel) !important;
  color: var(--text-primary) !important;
  border-color: var(--border-color) !important;
}
.leaflet-control-zoom a:hover {
  background: var(--bg-panel-hover) !important;
}
