async function testComputeSeaStatusScoreClamped() {
  // Near-gale winds + rough seas + heavy rain + low pressure — many penalties
  const result = functions.call('computeSeaStatus', {
    windSpeed: 35,
    windGusts: 50,
    waveHeight: 4.5,
    precipitation: 10,
    pressure: 988,
    cloudCover: 100
  });

  assert(result.score >= 0, 'Score should never be negative, got ' + result.score);
  assert(result.score <= 100, 'Score should never exceed 100, got ' + result.score);
  // With this many penalties, should be red or black
  assert(result.level === 'red' || result.level === 'black',
    'Extreme conditions should be red or black, got ' + result.level);
}
